// 12 insurance video review templates. {{variables}} are personalized
// at render time by the script-generator (B7.1).
const templates = [
  { trigger_event: 'birthday', tone: 'celebratory', cta_text: 'Reply or book a quick chat', recommended_persona_id: 'sarah', recommended_look_id: 'blazer', duration_seconds: 60, script_template: 'Hi {{first_name}}, happy birthday! As your insurance advisor at {{advisor_company}}, I want you to know we are thinking of you on your special day. Your {{policy_count}} policies are still working hard to protect you. Quick question: has anything changed in your life this year that we should review? New family member, new home, new job? Reply to this video or book a quick 15-minute review call.' },
  { trigger_event: 'new_job', tone: 'congratulatory', cta_text: 'Let me review your new benefits with you', recommended_persona_id: 'james', recommended_look_id: 'suit', duration_seconds: 70, script_template: 'Hi {{first_name}}, congratulations on your new role at {{new_company}}. As your insurance advisor I wanted to flag something important — new jobs often come with changes to your benefits package. Your current policies were designed for your previous situation. Lets take 15 minutes to make sure your coverage still fits. Want to compare what your new employer offers vs your current policies? Reply with what changed or book a call.' },
  { trigger_event: 'marriage', tone: 'celebratory', cta_text: 'Let me help you protect what matters most', recommended_persona_id: 'sarah', recommended_look_id: 'blazer', duration_seconds: 70, script_template: 'Hi {{first_name}}, congratulations on your marriage. As your insurance advisor I want to make sure your coverage matches your new chapter. Specifically: your beneficiaries probably need updating, you might want joint coverage, and tax implications change for married couples. Small adjustments now can save thousands later. Want to chat for 20 minutes about what makes sense?' },
  { trigger_event: 'baby', tone: 'celebratory', cta_text: 'Let me make sure your family is fully protected', recommended_persona_id: 'maria', recommended_look_id: 'warm', duration_seconds: 75, script_template: 'Hi {{first_name}}, congratulations on the new addition to your family. As your insurance advisor I want to share something important — having a child is the moment most families realize they need to update their coverage. Beneficiary designations, coverage amounts, guardianship considerations — all of these need attention now. Usually takes 20 minutes to make sure your family is fully protected. When works for a quick chat?' },
  { trigger_event: 'home_purchase', tone: 'congratulatory', cta_text: 'Let me review your complete coverage situation', recommended_persona_id: 'james', recommended_look_id: 'suit', duration_seconds: 70, script_template: 'Hi {{first_name}}, congratulations on the new home. Quick reminder from your insurance advisor: your new home means you need home insurance (different from a previous renters or homeowners policy), your life insurance might need adjustment to match your mortgage, and you might qualify for multi-policy bundling discounts. Let me put together a comprehensive review of your situation. Reply or book a 20-minute call.' },
  { trigger_event: 'business_expansion', tone: 'congratulatory', cta_text: 'Let me protect your growing business', recommended_persona_id: 'james', recommended_look_id: 'suit', duration_seconds: 75, script_template: 'Hi {{first_name}}, exciting to see {{business_name}} growing. As your insurance advisor I wanted to reach out. Business expansion often means new coverage needs — commercial liability, key person insurance, employee benefits, business interruption. Your current policies might not cover your new scale. Lets spend 30 minutes mapping what you have vs what you need.' },
  { trigger_event: 'job_loss', tone: 'supportive', cta_text: 'I am here to support you through this', recommended_persona_id: 'maria', recommended_look_id: 'warm', duration_seconds: 70, script_template: 'Hi {{first_name}}, I heard you are going through a transition. As your insurance advisor I want you to know I am here to help, not sell. Three things to know: your current policies have grace periods if cash flow gets tight, you may qualify for premium reductions, and there are ways to maintain coverage while you are between roles. Lets have a no-pressure call to figure out the best path. Reply with any questions.' },
  { trigger_event: 'annual_review_due', tone: 'informative', cta_text: 'Book your annual review', recommended_persona_id: 'sarah', recommended_look_id: 'blazer', duration_seconds: 60, script_template: 'Hi {{first_name}}, this is your friendly reminder that we are due for our annual policy review. It has been about a year since we last looked together. The world changes, your life changes, and I want to make sure your coverage still fits. We will cover any life changes, premium optimization, beneficiary updates, and emerging needs. Should take 20-30 minutes. Pick a time that works for you below.' },
  { trigger_event: 'renewal_due', tone: 'informative', cta_text: 'See your renewal options', recommended_persona_id: 'james', recommended_look_id: 'suit', duration_seconds: 65, script_template: 'Hi {{first_name}}, your {{product_type}} policy is up for renewal in {{days_until_renewal}} days. Before you auto-renew, let me show you something I have been working on. I reviewed comparable products from {{carrier_count}} other carriers. There may be better options now, or your current policy may still be best. Either way you should know your options. Want a quick comparison? Free and takes 15 minutes.' },
  { trigger_event: 'claim_filed', tone: 'supportive', cta_text: 'I am here to support you through your claim', recommended_persona_id: 'maria', recommended_look_id: 'warm', duration_seconds: 70, script_template: 'Hi {{first_name}}, I saw you filed a claim. As your advisor I am here to help you through this process. Claims can be stressful, but I will be your advocate. Three things to know: I will coordinate directly with the carrier on your behalf, here is what to expect timeline-wise, and dont sign anything without checking with me first. Call or message me anytime — I am here for you.' },
  { trigger_event: 'retirement_planning_age', tone: 'informative', cta_text: 'Plan your retirement coverage', recommended_persona_id: 'james', recommended_look_id: 'suit', duration_seconds: 70, script_template: 'Hi {{first_name}}, you are entering an exciting life phase. As you approach retirement your insurance needs evolve. Some policies become more valuable, others might be adjusted. Tax-efficient strategies become important. Lets spend 30 minutes mapping out your insurance for retirement and beyond. I will bring options, you bring questions.' },
  { trigger_event: 'child_milestone', tone: 'celebratory', cta_text: 'Lets talk about smart adjustments', recommended_persona_id: 'maria', recommended_look_id: 'warm', duration_seconds: 70, script_template: 'Hi {{first_name}}, your {{child_name}} reached an important milestone. Children milestones (graduation, marriage, first home) are great moments to revisit your insurance. Education funding, estate planning, generational wealth — small adjustments can have huge impact. Want to chat about what is smart at this stage? Free, no-pressure conversation.' }
];
return templates.map(function (t) { return { json: Object.assign({ vertical_id: 'insurance', active: true }, t) }; });
